const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
const T = input[idx++];
let results = [];
function gcd(a, b) { while (b !== 0) { const t = a % b; a = b; b = t; } return a; }
for (let tc = 0; tc < T; ++tc) {
  const N = input[idx++];
  const M = input[idx++];
  let g = 0;
  for (let i = 0; i < M; ++i) {
    const p = input[idx++];
    g = i === 0 ? p : gcd(g, p);
  }
  let best = 1;
  for (let d = 1; d * d <= g; ++d) {
    if (g % d === 0) {
      const d1 = d;
      const d2 = g / d;
      if (d1 <= N && d1 > best) best = d1;
      if (d2 <= N && d2 > best) best = d2;
    }
  }
  results.push(String(N - best));
}
console.log(results.join('\n'));
